func ProcessBatch(ctx context.Context, items []Item) ([]Result, error) {
    results := make([]Result, 0)
    for _, item := range items {
        r, err := process(ctx, item)
        if err != nil {
            log.Printf("failed to process item %v: %v", item.ID, err)
            continue
        }
        results = append(results, r)
    }
    if len(results) == 0 && len(items) > 0 {
        return nil, errors.New("all items failed")
    }
    return results, nil
}

